// HasAssetType applies the HasEdge predicate on the "asset_type" edge.
func HasAssetType() predicate.Asset {
	return predicate.Asset(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, AssetTypeTable, AssetTypeColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasAssetTypeWith applies the HasEdge predicate on the "asset_type" edge with a given conditions (other predicates).
func HasAssetTypeWith(preds ...predicate.AssetType) predicate.Asset {
	return predicate.Asset(func(s *sql.Selector) {
		step := newAssetTypeStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

